/*
KAMPÜS AKILLI YÖNETİM SİSTEMİ 
CAMPUS SMART MANAGEMENT SYSTEM 
*/

/*
AŞAMA 1: VERİTABANI KURULUMU (FRESH INSTALL)
Sıfırdan bir temiz sayfa açıyoruz. Türkçe karakterleri (ş, ğ, ı, ü, ö) SQL'in 
karıştırmaması için 'Turkish_CI_AS' ayarını kullanıyoruz.
We start with a clean slate. 'Turkish_CI_AS' ensures local characters work smoothly.
*/
CREATE DATABASE SmartCampusDB COLLATE Turkish_CI_AS;
GO

USE SmartCampusDB;
GO

/*
AŞAMA 2: TEMEL TABLOLAR (SİSTEMİN İSKELETİ / THE SKELETON)
Burada kampüsün ana taşlarını (insanlar, odalar, roller) tanımlıyoruz.
Defining the primary blocks: people, places, and rules.
*/

-- Roles: Kimin ne yetkisi var? (Öğrenci, Personel, Admin).
-- Roles: Defines access levels for different user types.
CREATE TABLE Roles (
    RoleID INT IDENTITY (1, 1) PRIMARY KEY,
    RoleName NVARCHAR (50) NOT NULL UNIQUE
);

-- FacilityTypes: "Nereye rezervasyon yapabilirim?" sorusunun cevabı. (Kütüphane, Laboratuvar vb.)
-- FacilityTypes: Categorizes spaces like Libraries or Study Rooms for filtered searching.
CREATE TABLE FacilityTypes (
    TypeID INT IDENTITY (1, 1) PRIMARY KEY,
    TypeName NVARCHAR (100) NOT NULL UNIQUE
);

-- Statuses: Rezervasyonun o anki ruh hali (Onaylandı, İptal, Beklemede).
-- Statuses: Monitors the lifecycle of a booking.
CREATE TABLE Statuses (
    StatusID INT IDENTITY (1, 1) PRIMARY KEY,
    StatusName NVARCHAR (50) NOT NULL UNIQUE
);

-- Users: Kampüsün gerçek sakinleri.
-- Email her zaman tekildir (UNIQUE). Ad-Soyadı sürekli birleştirmekle uğraşmamak için
-- 'FullName' alanını SQL'e otomatik hesaplattırıyoruz (FirstName + LastName).
-- Users: The community members. 'FullName' is computed automatically for efficiency.
CREATE TABLE Users (
    UserID INT IDENTITY (1, 1) PRIMARY KEY,
    FirstName NVARCHAR (50),
    LastName NVARCHAR (50),
    Email NVARCHAR (150) UNIQUE,
    PasswordHash NVARCHAR (256),
    CreatedAt DATETIME DEFAULT GETDATE (),
    IsActive BIT DEFAULT 1,
    FullName AS (FirstName + ' ' + LastName) PERSISTED
);

-- UserRoles: Bir kullanıcı aynı anda hem kütüphaneci hem öğrenci olabilir mi? Evet.
-- Bu tablo sayesinde bir kişiye birden fazla unvan verebiliyoruz.
-- UserRoles: A bridge table allowing one user to hold multiple roles.
CREATE TABLE UserRoles (
    UserID INT REFERENCES Users (UserID),
    RoleID INT REFERENCES Roles (RoleID),
    PRIMARY KEY (UserID, RoleID)
);

-- Zones: Kampüsü katlara ve bloklara böldüğümüz harita.
-- 'ParentZoneID' sayesinde "A Blok > 2. Kat" gibi iç içe yapılar kurabiliyoruz.
-- Zones: Maps the physical layout. Supports hierarchical locations via 'ParentZoneID'.
CREATE TABLE Zones (
    ZoneID INT IDENTITY (1, 1) PRIMARY KEY,
    ZoneName NVARCHAR (100) UNIQUE,
    Building NVARCHAR (100),
    FloorNo INT,
    ParentZoneID INT REFERENCES Zones (ZoneID)
);

-- Facilities: Rezervasyon yapılan asıl mekanlar.
-- 'MaxCapacity' çok önemli; doluluk oranlarını hep bu sayıya göre hesaplayacağız.
-- Facilities: The bookable rooms. 'MaxCapacity' serves as the anchor for occupancy math.
CREATE TABLE Facilities (
    FacilityID INT IDENTITY (1, 1) PRIMARY KEY,
    ZoneID INT REFERENCES Zones (ZoneID),
    TypeID INT REFERENCES FacilityTypes (TypeID),
    FacilityName NVARCHAR (150),
    MaxCapacity INT,
    IsReservable BIT DEFAULT 1,
    IsOperational BIT DEFAULT 1,
    OpenTime TIME DEFAULT '08:00',
    CloseTime TIME DEFAULT '22:00'
);

-- Sensors: Mekanların içindeki "gözlerimiz".
-- Her odada bir sensör olduğunu hayal et ve MAC adresi üzerinden onlara sesleniyoruz.
-- Sensors: Our "eyes" inside rooms. Linked via physical MAC addresses.
CREATE TABLE Sensors (
    SensorID INT IDENTITY (1, 1) PRIMARY KEY,
    FacilityID INT REFERENCES Facilities (FacilityID) ON DELETE CASCADE,
    SensorMac NVARCHAR (17) UNIQUE,
    IsActive BIT DEFAULT 1
);

-- OccupancyLogs: Kampüsün hafızası. Sensörlerden saniyeler içinde binlerce veri akıyor.
-- 'BIGINT' kullanıyoruz çünkü milyonlarca doluluk kaydı birikecek.
-- OccupancyLogs: High-volume time-series database. Uses BIGINT for scale.
CREATE TABLE OccupancyLogs (
    LogID BIGINT IDENTITY (1, 1) PRIMARY KEY,
    SensorID INT REFERENCES Sensors (SensorID) ON DELETE CASCADE,
    LoggedAt DATETIME DEFAULT GETDATE (),
    CurrentCount INT
);

-- Reservations: Kim, nereyi, ne zaman kapattı?
-- Reservations: Tracks who booked what and when.
CREATE TABLE Reservations (
    ReservationID BIGINT IDENTITY (1, 1) PRIMARY KEY,
    FacilityID INT REFERENCES Facilities (FacilityID) ON DELETE CASCADE,
    OrganizerUserID INT REFERENCES Users (UserID),
    StatusID INT REFERENCES Statuses (StatusID),
    StartTime DATETIME,
    EndTime DATETIME,
    CreatedAt DATETIME DEFAULT GETDATE (),
    CancelledAt DATETIME
);

-- ReservationAttendees: "Odayı ben tuttum ama arkadaşlarım da gelip gelmedi mi?" masası.
-- Bu tablo sayesinde her misafiri tek tek takip edebiliyoruz.
-- ReservationAttendees: Tracks invited guests and their show/no-show status.
CREATE TABLE ReservationAttendees (
    ReservationID BIGINT REFERENCES Reservations (ReservationID) ON DELETE CASCADE,
    UserID INT REFERENCES Users (UserID),
    IsAttended BIT DEFAULT 0,
    CheckedInAt DATETIME,
    PRIMARY KEY (ReservationID, UserID)
);

-- UserPenalties: Kampüs kuralları sert!
-- Rezervasyon yapıp gelmeyenlere buradan otomatik ceza puanları kesiyoruz.
-- UserPenalties: Automated penalty issuance for missed bookings to ensure fair room use.
CREATE TABLE UserPenalties (
    PenaltyID INT IDENTITY (1, 1) PRIMARY KEY,
    UserID INT REFERENCES Users (UserID),
    ReservationID BIGINT REFERENCES Reservations (ReservationID) ON DELETE CASCADE,
    PenaltyPoints INT DEFAULT 1,
    IssuedAt DATETIME DEFAULT GETDATE (),
    ExpiresAt DATETIME,
    IsActive BIT DEFAULT 1
);
GO

/*
AŞAMA 3: GÖRÜNÜMLER (SİSTEMİN VİTRİNİ / PREPARED VIEWS)
JOIN'ler ile her seferinde uğraşmamak için veriyi hazır hale getiriyoruz.
Prepared queries that simplify deep table joins into single virtual tables.
*/

/*
vw_LiveOccupancy: Dashboard'un en can alıcı yeri.
MANTIK:
1. 'LatestPerSensor' kısmında milyarlarca kayıttan her sensör için "SADECE EN SON" veriyi çekiyoruz (rn=1).
2. 'Facilities' ile birleştiriyoruz çünkü o an sensörden gelen sayıyı mekan ismiyle eşleştirmemiz lazım.
3. 'Zones' ile birleştiriyoruz ki o mekanın hangi binada/katta olduğunu bilelim.
4. 'OccupancyPct' (Doluluk Yüzdesi) hesaplıyoruz: (İçerideki Kişi / Kapasite) * 100.

vw_LiveOccupancy: The engine behind the real-time heatmaps.
LOGIC:
1. Filter through every log to grab strictly the "Very Last" reading for each sensor.
2. JOIN Facilities to pair that raw count with a physical room name and its capacity.
3. JOIN Zones to contextually display where this room is (Building/Floor).
4. Perform the Math: (Current Count / Max Capacity) * 100 to get the occupancy percentage.
*/
CREATE VIEW vw_LiveOccupancy AS
WITH
    LatestPerSensor AS (
        SELECT
            SensorID,
            CurrentCount,
            LoggedAt,
            ROW_NUMBER() OVER (
                PARTITION BY
                    SensorID
                ORDER BY LoggedAt DESC
            ) AS rn
        FROM OccupancyLogs
    )
SELECT
    f.FacilityID,
    f.FacilityName,
    z.ZoneName,
    ft.TypeName AS FacilityType,
    f.MaxCapacity,
    f.IsReservable,
    ISNULL(l.CurrentCount, 0) AS LiveCount,
    -- (Current / Max) * 100 with 2 decimal precision.
    CAST(
        ISNULL(l.CurrentCount, 0) * 100.0 / f.MaxCapacity AS DECIMAL(18, 2)
    ) AS OccupancyPct,
    l.LoggedAt AS LastUpdated,
    -- Humanized crowd level text.
    CASE
        WHEN ISNULL(l.CurrentCount, 0) = 0 THEN N'Empty'
        WHEN ISNULL(l.CurrentCount, 0) * 1.0 / f.MaxCapacity < 0.5 THEN N'Low'
        WHEN ISNULL(l.CurrentCount, 0) * 1.0 / f.MaxCapacity < 0.8 THEN N'Moderate'
        WHEN ISNULL(l.CurrentCount, 0) * 1.0 / f.MaxCapacity < 1.0 THEN N'High'
        ELSE N'Over Capacity'
    END AS CrowdLevel
FROM
    Facilities f
    JOIN Zones z ON f.ZoneID = z.ZoneID
    JOIN FacilityTypes ft ON f.TypeID = ft.TypeID
    JOIN Sensors s ON f.FacilityID = s.FacilityID
    LEFT JOIN LatestPerSensor l ON s.SensorID = l.SensorID
    AND l.rn = 1
WHERE
    f.IsOperational = 1;
GO

/*
vw_TodayReservations: Sadece "Bugünün" ne kadar yoğun geçeceğini gösterir.
MANTIK / LOGIC:
- 'Reservations' tablosundan çekiyoruz, 'Users' ile bağlayıp kimin tuttuğunu gösteriyoruz. / Fetch from Reservations, JOIN Users to show organizers.
- 'ReservationAttendees' ile bağlayıp o rezervasyona toplam kaç kişinin davetli olduğunu saydırıyoruz. / JOIN ReservationAttendees to count total guests.

vw_TodayReservations: A filtered glance at today's schedule. Count attendees per booking.
*/
CREATE VIEW vw_TodayReservations AS
SELECT
    r.ReservationID,
    f.FacilityName,
    u.FullName AS Organizer,
    st.StatusName,
    r.StartTime,
    r.EndTime,
    DATEDIFF(
        MINUTE,
        r.StartTime,
        r.EndTime
    ) AS DurationMin,
    COUNT(ra.UserID) AS AttendeeCount,
    r.OrganizerUserID
FROM
    Reservations r
    JOIN Facilities f ON r.FacilityID = f.FacilityID
    JOIN Users u ON r.OrganizerUserID = u.UserID
    JOIN Statuses st ON r.StatusID = st.StatusID
    LEFT JOIN ReservationAttendees ra ON r.ReservationID = ra.ReservationID
WHERE
    CAST(r.StartTime AS DATE) = CAST(GETDATE () AS DATE)
GROUP BY
    r.ReservationID,
    f.FacilityName,
    u.FullName,
    st.StatusName,
    r.StartTime,
    r.EndTime,
    r.OrganizerUserID;
GO

/*
AŞAMA 4: PROSEDÜRLER (İŞ MANTIĞI / THE BRAIN)
Karışık işlemleri buraya gömüyoruz ki kod kısmı tertemiz kalsın.
Logical encapsulation: Keep the logic in the DB to make the App code slim.
*/

/*
sp_GetLiveHeatmap: Tek tıkla kampüsün röntgenini çeker.
Hangi bina cayır cayır yanıyor (dolu), hangisi bomboş buradan süzülür.
sp_GetLiveHeatmap: A one-click X-ray of the campus. 
Visualizes which buildings are buzzing (crowded) and which are empty.
*/
CREATE PROCEDURE sp_GetLiveHeatmap AS
BEGIN
    SET NOCOUNT ON; -- Pre-performance boost / Performans artışı için.
    SELECT * FROM vw_LiveOccupancy;
END;
GO

/*
sp_GetUserDashboard: Bir öğrenci girdiğinde ona her şeyi bir tepside sunarız.
MANTIK / LOGIC:
1. Ona ait gelecek rezervasyonları listeler. / Lists their upcoming bookings.
2. Geçmişteki performansını (Kaç derse geldi/gelmedi) özetler. / Summarizes past attendance performance.
3. Ceza puanı varsa "bak dikkat et" uyarısı için veriyi getirir. / Fetches penalty data for warnings.
4. Genel kampüs durumunu (Heatmap) da en sona yapıştırır. / Appends the general campus heatmap at the end.
*/
CREATE PROCEDURE sp_GetUserDashboard @UserID INT AS
BEGIN
    SET NOCOUNT ON;
    -- Kişiye özel gelecek rezervasyonlar / User's upcoming slots.
    SELECT r.ReservationID, f.FacilityName, r.StartTime, r.EndTime, st.StatusName 
    FROM Reservations r JOIN Facilities f ON r.FacilityID = f.FacilityID 
    JOIN Statuses st ON r.StatusID = st.StatusID 
    WHERE r.OrganizerUserID = @UserID AND r.StartTime > GETDATE() ORDER BY r.StartTime;

    -- Katılım Karnesi / Attendance Scorecard.
    SELECT COUNT(*) AS TotalBookings, SUM(CAST(ra.IsAttended AS INT)) AS Attended, 
           SUM(1-CAST(ra.IsAttended AS INT)) AS Missed, 
           CAST(SUM(CAST(ra.IsAttended AS INT))*100.0/NULLIF(COUNT(*),0) AS DECIMAL(18,2)) AS AttendanceRate 
    FROM ReservationAttendees ra WHERE ra.UserID = @UserID;

    -- Mevcut cezalar / Current active penalties.
    SELECT COUNT(*) AS ActivePenalties, SUM(PenaltyPoints) AS TotalPoints, 
           MIN(ExpiresAt) AS EarliestExpiry FROM UserPenalties WHERE UserID = @UserID AND IsActive = 1;

    -- Genel durum / All campus heatmap.
    EXEC sp_GetLiveHeatmap;
END;
GO

/*
sp_GetNoShowReport: Adminlerin "kara listesi".
MANTIK:
- Rezervasyon yapan ama o kapıdan içeri girmeyen (rn=rn) kişileri tespit eder.
- Eğer %50'den fazlasına gelmemişse "Yüksek Risk" etiketini yapıştırır.
sp_GetNoShowReport: Identifies flaky users and labels them by booking risk level.
*/
CREATE PROCEDURE sp_GetNoShowReport AS
BEGIN
    SET NOCOUNT ON;
    SELECT
        u.UserID, u.FullName,
        COUNT(ra.ReservationID) AS TotalBookings,
        SUM(CAST(ra.IsAttended AS INT)) AS AttendedCount,
        SUM(1 - CAST(ra.IsAttended AS INT)) AS MissedCount,
        -- Calculate percentage avoiding integer division problems.
        CAST(SUM(1.0 - CAST(ra.IsAttended AS INT)) * 100.0 / NULLIF(COUNT(*), 0) AS DECIMAL(18,2)) AS NoShowRate,
        CASE
            WHEN SUM(1.0 - CAST(ra.IsAttended AS FLOAT)) / NULLIF(COUNT(*), 0) >= 0.5 THEN N'High Risk'
            WHEN SUM(1.0 - CAST(ra.IsAttended AS FLOAT)) / NULLIF(COUNT(*), 0) >= 0.25 THEN N'Moderate Risk'
            ELSE N'Good Standing'
        END AS RiskLabel
    FROM Users u
    JOIN ReservationAttendees ra ON u.UserID = ra.UserID
    GROUP BY u.UserID, u.FullName
    HAVING COUNT(ra.ReservationID) >= 3 -- En az 3 rezervasyon yapmış olanları ciddiye al. / Only consider users with 3+ bookings.
    ORDER BY NoShowRate DESC;
END;
GO

/*
sp_GetPeakHours: "Ne zaman gitmeliyim?" sorusunun cevabı.
MANTIK:
- Geçmiş loglara bakar, her saat dilimi (08:00, 09:00...) için ortalama kalabalığı hesaplar.
- En yoğun saati 1. sıraya (BusiestRank) yerleştirir.
sp_GetPeakHours: Historical analysis to find the "rush hour" of any facility.
*/
CREATE PROCEDURE sp_GetPeakHours @FacilityID INT AS
BEGIN
    SET NOCOUNT ON;
    WITH HourlyAvg AS (
        SELECT
            DATEPART(HOUR, l.LoggedAt) AS HourOfDay,
            AVG(CAST(l.CurrentCount AS FLOAT)) AS AvgOccupancyRaw,
            MAX(l.CurrentCount) AS PeakOccupancy
        FROM OccupancyLogs l
        JOIN Sensors s ON l.SensorID = s.SensorID
        WHERE s.FacilityID = @FacilityID
        GROUP BY DATEPART(HOUR, l.LoggedAt)
    )
    SELECT 
        HourOfDay, 
        CAST(AvgOccupancyRaw AS INT) AS AvgOccupancy, 
        PeakOccupancy,
        RANK() OVER (ORDER BY AvgOccupancyRaw DESC) AS BusiestRank
    FROM HourlyAvg ORDER BY HourOfDay;
END;
GO

/*
sp_SuggestAlternatives: Mekan doluysa kullanıcıyı boş çevirmeyip alternatif bulan sistem.
MANTIK / LOGIC:
1. 'Conflicts' içinde: İstediğin saatte dolu (Approved) olan yerleri listeler ve dışlarız. / Exclude rooms already booked.
2. Aynı tipten (Örn: Derslik) olan diğer yerleri 'vw_LiveOccupancy' ile eşleştirip anlık durumuna bakarız. / Check live status of same-type rooms.
3. En boş olanı en üste yazarız (RANK). / Rank by availability (SuggestionRank).

sp_SuggestAlternatives: Finding the quietest alternative spot if the request has a conflict.
*/
CREATE PROCEDURE sp_SuggestAlternatives @TypeID INT, @Start DATETIME, @End

DATETIME AS BEGIN SET NOCOUNT ON;

DECLARE @ApprovedID INT = (SELECT StatusID FROM Statuses WHERE StatusName = N'Approved');
    WITH Conflicts AS (
        SELECT DISTINCT FacilityID FROM Reservations
        WHERE StatusID = @ApprovedID AND StartTime < @End

AND EndTime > @Start
    )
    SELECT
        f.FacilityID, f.FacilityName, z.ZoneName, f.MaxCapacity, lo.LiveCount AS CurrentOccupancy, lo.OccupancyPct,
        RANK() OVER (ORDER BY lo.LiveCount ASC) AS SuggestionRank
    FROM Facilities f 
    JOIN Zones z ON f.ZoneID = z.ZoneID
    JOIN vw_LiveOccupancy lo ON f.FacilityID = lo.FacilityID
    WHERE f.TypeID = @TypeID AND f.IsReservable = 1 AND f.IsOperational = 1
      AND f.FacilityID NOT IN (SELECT FacilityID FROM Conflicts) 
    ORDER BY SuggestionRank;

END;
GO

/*
sp_FindFreeSlots: Mekanın o günkü takvimindeki boş delikleri bulur.
MANTIK / LOGIC:
- 08:00 ile 22:00 arasını saat saat dilimleriz. / Slice the day into 1-hour slots from 08:00 to 22:00.
- Hiçbir rezervasyonla çakışmayan (NOT EXISTS) saatleri listeleriz. / List hours that don't overlap with any bookings.

sp_FindFreeSlots: Generates a 1-hour interval list of gaps in the daily calendar.
*/
CREATE PROCEDURE sp_FindFreeSlots @FacilityID INT, @Date DATE AS
BEGIN
    SET NOCOUNT ON;
    DECLARE @OpenDT DATETIME = CAST(@Date AS DATETIME) + '08:00', @CloseDT DATETIME = CAST(@Date AS DATETIME) + '22:00';
    WITH Slots AS (
        SELECT @OpenDT AS SlotStart, DATEADD(HOUR,1,@OpenDT) AS SlotEnd
        UNION ALL SELECT DATEADD(HOUR,1,SlotStart), DATEADD(HOUR,1,SlotEnd) FROM Slots WHERE DATEADD(HOUR,1,SlotEnd) <= @CloseDT
    )
    SELECT sl.SlotStart, sl.SlotEnd FROM Slots sl
    WHERE NOT EXISTS (
        SELECT 1 FROM Reservations r 
        WHERE r.FacilityID = @FacilityID AND r.StatusID = 2 
          AND r.StartTime < sl.SlotEnd AND r.EndTime > sl.SlotStart
    )
    OPTION (MAXRECURSION 24);
END;
GO

